const d = $json;

if (!d.base || !d.new) {
  return [{ json: { error: "Missing data" } }];
}

const base = d.base;
const newData = d.new;

// condition logic
let condition = "Good";
if (base.life < 40) condition = "Critical";
else if (base.life < 70) condition = "Warning";

return [
  {
    json: {
      prediction: {
        tool_wear: base.wear,
        condition: condition,
        remaining_life: base.life
      },
      what_if: {
        change: `Speed ${base.speed} → ${newData.speed}`,
        impact: `Life drops from ${base.life.toFixed(2)} → ${newData.life.toFixed(2)}`
      }
    }
  }
];

const input = $json.body;

const speed = input.cuttingSpeed;
const feed = input.feedRate;
const depth = input.depthOfCut;

const wear = 0.02 * speed + 0.03 * feed + 0.01 * depth;
const life = 100 - wear;

return [
  {
    json: {
      speed,
      feed,
      depth,
      wear,
      life
    }
  }
];

const d = $json;

const speed = d.speed ?? 0;
const feed = d.feed ?? 0;
const depth = d.depth ?? 0;

const baseWear = d.wear ?? 0;
const baseLife = d.life ?? 0;

const newSpeed = speed * 1.2;

const newWear = 0.02 * newSpeed + 0.03 * feed + 0.01 * depth;
const newLife = 100 - newWear;

return [
  {
    json: {
      base: {
        speed,
        wear: baseWear,
        life: baseLife
      },
      new: {
        speed: newSpeed,
        wear: newWear,
        life: newLife
      }
    }
  }
];
